inbound.set-body:
@{
            var raw = context.Request.Body.As<string>(preserveContent: true) ?? "";
            var pairs = raw.Split('&');
            var kept = new System.Collections.Generic.List<string>();
            bool hasClientSecret = false;
            foreach (var p in pairs)
            {
                if (string.IsNullOrEmpty(p)) { continue; }
                var eq = p.IndexOf('=');
                var key = eq >= 0 ? p.Substring(0, eq) : p;
                if (key.Equals("resource", System.StringComparison.OrdinalIgnoreCase)) { continue; }
                if (key.Equals("scope", System.StringComparison.OrdinalIgnoreCase)) { continue; }
                if (key.Equals("client_secret", System.StringComparison.OrdinalIgnoreCase)) { hasClientSecret = true; }
                kept.Add(p);
            }
            kept.Add("scope=" + System.Net.WebUtility.UrlEncode("https://api.fabric.microsoft.com/.default offline_access openid profile"));
            if (!hasClientSecret)
            {
                kept.Add("client_secret={{fabric-mcp-client-secret}}");
            }
            return string.Join("&", kept);
        }
